('spanish:x-2-reading-and-translation-into-english:mcq:bc617022', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Fui al cine ayer.\" data-listen></span><br>Listen. What is the correct translation?", "options": ["I go to the cinema every day", "I went to the cinema yesterday", "I am going to the cinema now", "I have been to the cinema many times before"]}'::jsonb, '{"answer": 1, "explain": "''fui'' = I went (pretérito, one completed past action). The traps swap to a habit, a present plan, or the present perfect."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:e1ebf70d', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "<span data-say=\"Iba al gimnasio todos los días.\" data-listen></span><br>Listen. What is the correct translation?", "options": ["I went to the gym just once, yesterday afternoon", "I have never really gone to the gym before", "I used to go to the gym every day", "I am going to the gym today, just this once"]}'::jsonb, '{"answer": 2, "explain": "''iba'' = I used to go (imperfecto, a repeated/ongoing past habit). Trap A wrongly uses the preterite (one single event)."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:9e71ab82', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "In the sentence <span data-say=\"Mi madre está embarazada.\">\"Mi madre está embarazada,\"</span> what does <em>embarazada</em> mean?", "options": ["pregnant", "embarrassed", "in a hurry", "on holiday"]}'::jsonb, '{"answer": 0, "explain": "embarazada = pregnant. It is a classic false friend — it does NOT mean embarrassed."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:ca6161bd', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "What does <em>sensible</em> mean when used in Spanish, as in <span data-say=\"Es una persona muy sensible.\">\"Es una persona muy sensible\"</span>?", "options": ["sensible / practical", "intelligent", "friendly", "sensitive"]}'::jsonb, '{"answer": 3, "explain": "sensible = sensitive. The English-looking meaning (''sensible/practical'') is the false-friend trap."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:b8e4bf35', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "Read: \"Los científicos descubrieron una nueva especie de pájaro en la selva.\" Using the word family \"des-\" + \"cubrir\" (to cover), what does <em>descubrieron</em> most likely mean?", "options": ["covered up", "destroyed", "described", "discovered"]}'::jsonb, '{"answer": 3, "explain": "des- + cubrir → discovered/uncovered. ''covered up'' is the literal-but-wrong trap; ''destroyed'' and ''described'' sound similar but are wrong."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:1451cbe5', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "In Section A of Paper 3, how should you answer the comprehension questions (unless told otherwise)?", "options": ["Always in full Spanish sentences copied from the text", "In Spanish, using your own words only", "In English, or non-verbally (e.g. a tick or box)", "With a single Spanish word for every answer"]}'::jsonb, '{"answer": 2, "explain": "Section A questions are in English and answered in English or non-verbally. Copying Spanish sentences does not answer the question."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:7f5cb1b4', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "Which approach is correct for the Section B translation task?", "options": ["Translate every single word literally, one by one, in the exact Spanish word order", "Translate the sense of each phrase naturally, keeping the correct tense", "Skip any sentence containing a word you don''t recognise", "Copy the Spanish words directly into your English answer unchanged"]}'::jsonb, '{"answer": 1, "explain": "Translate the sense of each phrase and keep the tense. Word-for-word literal translation is the #1 error examiners penalise."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:2d4e98ab', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "Translate: <span data-say=\"Está constipado.\">\"Está constipado.\"</span>", "options": ["He is constipated", "He is very tired", "He is in a rush", "He has a cold"]}'::jsonb, '{"answer": 3, "explain": "constipado = having a cold. ''He is constipated'' is the obvious but wrong false-friend translation."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:1afa09e4', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "What is the minimum word count for the Section B translation at Higher tier?", "options": ["50 words", "35 words", "25 words", "100 words"]}'::jsonb, '{"answer": 0, "explain": "Higher tier requires a minimum of 50 words; Foundation requires 35 words — a common mix-up."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:mcq:b907f08f', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'mcq', 'mcq', 1, '{"question": "How many marks is the Section B translation task worth?", "options": ["40 marks", "25 marks", "10 marks", "50 marks"]}'::jsonb, '{"answer": 2, "explain": "Section B (translation) is worth 10 marks; 40 is Section A, 50 is the whole paper, 25 is the % weighting — not a mark total."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:65a657b3', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "Paper 3 is a listening exam."}'::jsonb, '{"answer": false, "explain": "Paper 3 is a WRITTEN Reading exam (45 min Foundation / 1 hour Higher)."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:566ed363', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "In Section A, you must answer the comprehension questions in English or non-verbally."}'::jsonb, '{"answer": true, "explain": "Section A questions are in English and answered in English or non-verbally (40 marks)."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:e72e58d7', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "Section B is a translation from Spanish into English worth 10 marks."}'::jsonb, '{"answer": true, "explain": "Section B = translation into English, 10 marks; minimum 35 (F) / 50 (H) words."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:f0fb8caa', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "The minimum word count for the Higher tier translation is 35 words."}'::jsonb, '{"answer": false, "explain": "35 words is the Foundation minimum — Higher tier needs a minimum of 50 words."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:0d8331c7', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "<span data-say=\"sensible\">''Sensible''</span> in Spanish means the same as ''sensible'' in English."}'::jsonb, '{"answer": false, "explain": "False friend — Spanish ''sensible'' means sensitive, not practical/sensible."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:8db24beb', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "When translating <span data-say=\"Fui al cine.\">\"Fui al cine\"</span> into English, you should keep the tense of the original Spanish verb."}'::jsonb, '{"answer": true, "explain": "''fui'' (went) and ''iba'' (used to go) must not be switched to the present tense in your translation."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:3043386f', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "If you don''t know a word in the translation, it''s best to leave that part blank."}'::jsonb, '{"answer": false, "explain": "Never leave a gap — use context, word families or cognates to make a sensible attempt."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tf:bd28f7b1', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tf', 'tf', 1, '{"question": "Paper 3 makes up 25% of the GCSE Spanish grade."}'::jsonb, '{"answer": true, "explain": "Each of the four skills papers (Listening, Speaking, Reading, Writing) is worth 25%."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:learn:1155c8bb', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'learn', 'mcq', 1, '{"readingTitle": "What does AQA Paper 3 actually test?", "reading": "<p>Paper 3 is a <strong>written Reading exam</strong>: <span data-say=\"cuarenta y cinco minutos\">45 minutes</span> at Foundation, <span data-say=\"una hora\">1 hour</span> at Higher. It is worth <strong>50 marks</strong> — <strong>25%</strong> of your final GCSE grade.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>Section A</td><td>Reading comprehension — questions <strong>in English</strong>, answered <strong>in English or non-verbally</strong> (a tick, box or letter). 40 marks. Includes inferring the meaning of an unknown word from context.</td></tr>\n              <tr><td>Section B</td><td><strong>Translation</strong> of a Spanish text <strong>into English</strong>. Minimum <span data-say=\"treinta y cinco palabras\">35 words</span> (Foundation) / <span data-say=\"cincuenta palabras\">50 words</span> (Higher). 10 marks.</td></tr>\n            </table>\n            <p>Instruction you will see on the paper: <span data-say=\"Traduce este texto al inglés.\">Traduce este texto al inglés.</span> — <em>Translate this text into English.</em></p>", "question": "How many marks is Paper 3 worth in total?", "options": ["50 marks", "40 marks", "60 marks", "25 marks"]}'::jsonb, '{"answer": 0, "explain": "Paper 3 is worth 50 marks in total — 40 for Section A and 10 for Section B — and is 25% of the GCSE."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:learn:df7aefbe', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'learn', 'mcq', 1, '{"readingTitle": "Section A: how to read strategically", "reading": "<p>Don''t read word by word from the top. Use a two-step strategy:</p>\n            <ol>\n              <li><strong>Skim</strong> the whole text quickly first, for the general gist — what is it about?</li>\n              <li>Then <strong>scan</strong> for the specific detail each question asks for.</li>\n            </ol>\n            <p>Spotting these connectors while skimming helps you follow the logic of a text:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"sin embargo\">sin embargo</span></td><td>however</td><td><span data-say=\"además\">además</span></td><td>furthermore / also</td></tr>\n              <tr><td><span data-say=\"por eso\">por eso</span></td><td>that''s why / so</td><td><span data-say=\"aunque\">aunque</span></td><td>although</td></tr>\n            </table>", "question": "What should you do FIRST when reading a text in Section A?", "options": ["Skim the whole text quickly for the general gist", "Look up every unknown word in a dictionary immediately", "Translate the entire text into English word by word", "Answer question 1 without reading the rest of the text"]}'::jsonb, '{"answer": 0, "explain": "Skim first for the gist, then scan for the specific detail each question needs — don''t translate the whole thing or dictionary-hunt every word."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:learn:39fd3a6c', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'learn', 'mcq', 1, '{"readingTitle": "Inferring the meaning of unknown words", "reading": "<p>Section A also tests whether you can work out a <strong>plausible meaning</strong> for a word you don''t already know, using context and word families — you are not expected to know every word.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"descubrir\">descubrir</span></td><td>des- + cubrir (to cover) → to discover / uncover</td></tr>\n              <tr><td><span data-say=\"inolvidable\">inolvidable</span></td><td>in- + olvidar (to forget) + -able → unforgettable</td></tr>\n              <tr><td><span data-say=\"desconocido\">desconocido</span></td><td>des- + conocido (known) → unknown</td></tr>\n              <tr><td><span data-say=\"rápidamente\">rápidamente</span></td><td>rápido (fast) + -mente → quickly</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Los científicos descubrieron una nueva especie de pájaro.\">Los científicos descubrieron una nueva especie de pájaro.</span> — <em>The scientists discovered a new species of bird.</em></p>", "question": "In ''descubrieron'' (des- + cubrir), what does the prefix ''des-'' generally signal?", "options": ["a reversal or undoing of the root word''s action", "that the word must be a false friend you cannot trust at all", "that the verb is definitely in the future tense", "that the word describes a physical size"]}'::jsonb, '{"answer": 0, "explain": "des- typically reverses or undoes the root: cubrir (to cover) → descubrir (to uncover/discover)."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:learn:b2491870', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'learn', 'mcq', 1, '{"readingTitle": "False friends — the #1 trap", "reading": "<p>A <strong>false friend</strong> looks like an English word but means something different. Learn these before Paper 3:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"sensible\">sensible</span></td><td>sensitive (NOT sensible)</td></tr>\n              <tr><td><span data-say=\"constipado\">constipado</span></td><td>having a cold (NOT constipated)</td></tr>\n              <tr><td><span data-say=\"éxito\">éxito</span></td><td>success (NOT exit)</td></tr>\n              <tr><td><span data-say=\"ropa\">ropa</span></td><td>clothes (NOT rope)</td></tr>\n              <tr><td><span data-say=\"largo\">largo</span></td><td>long (NOT large)</td></tr>\n              <tr><td><span data-say=\"embarazada\">embarazada</span></td><td>pregnant (NOT embarrassed)</td></tr>\n            </table>\n            <p>Examples: <span data-say=\"Mi madre está embarazada.\">Mi madre está embarazada.</span> (My mother is pregnant.) · <span data-say=\"Estoy constipado.\">Estoy constipado.</span> (I have a cold.)</p>", "question": "Which of these correctly matches the Spanish word to its true English meaning?", "options": ["constipado = having a cold", "sensible = sensible / practical", "éxito = an exit", "ropa = a rope"]}'::jsonb, '{"answer": 0, "explain": "constipado = having a cold. The other three are the WRONG literal guesses — exactly the false-friend trap examiners test."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:learn:a87373f6', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'learn', 'mcq', 1, '{"readingTitle": "Section B: how the translation is marked", "reading": "<p>Section B gives you a short Spanish text to translate <strong>into English</strong>. It is marked in <strong>chunks of meaning</strong>, not word by word — the examiner ticks each idea you translate correctly.</p>\n            <ul>\n              <li>Translate the <strong>sense</strong> of each phrase naturally — don''t translate word for word.</li>\n              <li>Keep the <strong>tense</strong> of the Spanish verb: <span data-say=\"fui\">fui</span> = I went (one completed action); <span data-say=\"iba\">iba</span> = I used to go / I was going (an ongoing or repeated action).</li>\n              <li>Idioms need a natural English equivalent: <span data-say=\"Se me olvidó el cumpleaños de mi amigo.\">Se me olvidó el cumpleaños de mi amigo.</span> = I forgot my friend''s birthday — NOT \"it forgot itself to me\".</li>\n              <li>Never leave a gap. If a word is unknown, use context or a cognate to make a sensible attempt.</li>\n            </ul>", "question": "Section B is worth how many marks, and what is it testing?", "options": ["10 marks — translating a Spanish passage into English", "40 marks — answering comprehension questions in English", "50 marks — the whole of Paper 3 combined", "25 marks — a mix of reading and writing tasks"]}'::jsonb, '{"answer": 0, "explain": "Section B is the translation task, worth 10 of the paper''s 50 marks."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:learn:727a86a9', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'learn', 'mcq', 1, '{"readingTitle": "Higher: tense accuracy and natural English", "reading": "<p><span class=\"tier-h\">H</span> Higher-tier translation passages add more complex tenses. You must still keep the tense in your English:</p>\n            <ul>\n              <li><span data-say=\"Había terminado los deberes antes de cenar.\">Había terminado los deberes antes de cenar.</span> <span class=\"tier-h\">H</span> — I had finished my homework before dinner (pluperfect: an action before another past action).</li>\n              <li><span data-say=\"Si tuviera más tiempo, viajaría más.\">Si tuviera más tiempo, viajaría más.</span> <span class=\"tier-h\">H</span> — If I had more time, I would travel more (conditional).</li>\n              <li><span data-say=\"Aunque llovía, decidimos salir.\">Aunque llovía, decidimos salir.</span> <span class=\"tier-h\">H</span> — Although it was raining, we decided to go out.</li>\n            </ul>\n            <p>Once you have a draft translation, always re-read it and ask: <em>does this sound like natural English, or does it sound translated?</em></p>", "question": "Which translation correctly reflects the tense of ''Había terminado los deberes antes de cenar''?", "options": ["I had finished my homework before having dinner", "I finish my homework before having dinner", "I will finish my homework before having dinner", "I am currently in the middle of finishing my homework before dinner"]}'::jsonb, '{"answer": 0, "explain": "''había terminado'' is the pluperfect — an action completed before another past action — so it must be ''I had finished''."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:misc:4b99a5a1', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Fui al cine. → translated as ''I go to the cinema.''</p><p><strong>✅ The correct idea:</strong> Fui al cine. → I went to the cinema. (pretérito = a completed action, not the present)</p>", "question": "What tense is ''fui'' in ''Fui al cine'', and what does that mean for the translation?", "options": ["Preterite — a single completed action, so it must be ''I went''", "Present — an ongoing habit, so it should be ''I go''", "Future — a plan, so it should be ''I will go''", "Imperfect — a repeated or ongoing action, so it should be ''I used to go''"]}'::jsonb, '{"answer": 0, "explain": "''fui'' is the preterite of ir — a single completed action in the past, so it must translate as ''I went''."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:misc:2fbfd4ae', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> <span data-say=\"Está constipado.\">Está constipado.</span> → ''He is constipated.''</p><p><strong>✅ The correct idea:</strong> Está constipado. → He has a cold. (false friend)</p>", "question": "Why is ''He is constipated'' the wrong translation of ''Está constipado''?", "options": ["''constipado'' is a false friend that actually means ''having a cold''", "''constipado'' is a rare medical term that never appears on a GCSE reading paper at all", "''está'' means ''he was'' in the imperfect tense, not ''he is'' right now", "the sentence is actually posed as a question, not a statement"]}'::jsonb, '{"answer": 0, "explain": "constipado = having a cold — a classic Spanish/English false friend."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:misc:234878cc', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Se me olvidó el libro. → translated word-for-word as ''It forgot itself to me the book.''</p><p><strong>✅ The correct idea:</strong> Se me olvidó el libro. → I forgot the book. (translate the natural English meaning, not each word)</p>", "question": "What is the natural English translation of ''Se me olvidó el libro''?", "options": ["I forgot the book", "It forgot itself to me the book", "The book has forgotten me completely", "I remembered the book just in time"]}'::jsonb, '{"answer": 0, "explain": "Idioms like ''se me olvidó'' need a natural English equivalent — ''I forgot'' — not a literal word-for-word rendering."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:misc:7343b5b4', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Leaving a gap in the translation because a word is unknown.</p><p><strong>✅ The correct idea:</strong> Use context, word family or a cognate to make a sensible, plausible attempt — never leave a gap.</p>", "question": "What should you do with a word you don''t recognise during the translation task?", "options": ["Use context and word-family clues to attempt a sensible translation", "Leave a blank gap so you don''t risk losing extra marks for a wrong guess", "Copy the Spanish word into your English answer unchanged", "Skip the whole sentence that word appears in"]}'::jsonb, '{"answer": 0, "explain": "You can often infer a plausible meaning from context, cognates or the word''s root — never leave a gap."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:misc:d6d92b65', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> <span data-say=\"Es una persona muy sensible.\">Es una persona muy sensible.</span> → ''He is a very sensible person.''</p><p><strong>✅ The correct idea:</strong> Es una persona muy sensible. → He is a very sensitive person. (false friend)</p>", "question": "Why is ''a very sensible person'' the wrong translation of ''una persona muy sensible''?", "options": ["Spanish ''sensible'' means sensitive, not practical/sensible", "''persona'' does not mean ''person'' at all anywhere in this whole sentence", "''muy'' changes the whole sentence into a question instead of a statement", "the sentence is written in the future tense, not the present"]}'::jsonb, '{"answer": 0, "explain": "sensible = sensitive in Spanish — the English-looking meaning is the false-friend trap."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tips:612054aa', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tips', 'mcq', 1, '{"readingTitle": "tip — Section A — skim, then scan", "reading": "Skim the whole text first for the general gist, then go back and scan for the specific detail each question needs. Don''t translate the whole text in your head before answering — that wastes time you need for later questions.", "question": "Why skim a text before answering any questions?", "options": ["To get the general gist quickly before hunting for detail", "Because the exam board requires a full written translation before you answer", "Because scanning for detail is not allowed anywhere in Section A", "To find and note down every single unknown word first"]}'::jsonb, '{"answer": 0, "explain": "Skimming gives you the gist fast; you then scan for the specific detail each question is really asking about."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tips:de260ef4', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tips', 'mcq', 1, '{"readingTitle": "tip — Section B — translate the sense, not the words", "reading": "Translate each phrase as a whole idea, keep the Spanish verb''s tense in your English, and make idioms sound natural (e.g. ''se me olvidó'' = ''I forgot'', not a literal word-for-word version). Never leave a translation gap — a sensible attempt can still earn marks.", "question": "''Estoy resfriado y me duele la garganta'' should be translated as…", "options": ["I have a cold and my throat hurts", "I have a cold and my throat hurt yesterday", "I am tired and my whole back hurts", "I am fit and my legs hurt after running"]}'::jsonb, '{"answer": 0, "explain": "estar resfriado = to have a cold; la garganta = throat. Keep it in the present tense, as in the Spanish."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:tips:e4aba03d', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Higher tier — tense accuracy earns marks", "reading": "At Higher tier, passages mix tenses: pretérito, imperfecto, pluperfect (''había + past participle'') and conditional (''-ría''). Translate each one accurately — swapping ''había terminado'' (had finished) for ''finished'' loses the mark even if the rest of the sentence is right.", "question": "Which English translation correctly matches ''Si tuviera más tiempo, viajaría más''?", "options": ["If I had more time, I would travel more", "If I have more time, I will travel more often", "I had more time, so I travelled more", "I would have had more time to travel more"]}'::jsonb, '{"answer": 0, "explain": "''tuviera'' (imperfect subjunctive) + ''viajaría'' (conditional) = the classic ''if I had… I would…'' structure."}'::jsonb),
('spanish:x-2-reading-and-translation-into-english:fib:2abaad80', 'spanish', 'spanish:x-2-reading-and-translation-into-english', 'X.2 Reading and Translation into English', 'fib', 'fib', 1, '{"question": "<span data-say=\"Fui al cine.\">Fui al cine.</span> = I _____ to the cinema. (pretérito — a completed action)", "blankOptions": {"B1": ["used", "went", "has", "long"]}}'::jsonb, '{"blanks": {"B1": "went"}}'::jsonb),
